import { chromium } from 'playwright';
import { readFileSync } from 'fs';

const cookies = JSON.parse(readFileSync('C:\\Users\\yyzypublic\\.openclaw\\workspace\\devops_cookies.json', 'utf-8'));

const browser = await chromium.launch({ headless: true });
const context = await browser.newContext();
await context.addCookies(cookies);

const page = await context.newPage();

console.log('Navigating to build page...');
await page.goto('https://devops.devcloud.ztgame.com/projects/yyzy/pipelines/p-f78c977835c84b71a6d58b4746cd1c4a?buildId=b-a872a3a41313452db446a47f694247f2', {
  waitUntil: 'networkidle',
  timeout: 30000
});

// Click on #1084 in the history list
console.log('Looking for #1084...');

// Try to find text containing 1084
const build1084 = await page.locator('text=#1084').first();
if (await build1084.isVisible()) {
  console.log('#1084 found, clicking...');
  await build1084.click();
  await page.waitForTimeout(3000);
  await page.screenshot({ path: 'C:\\Users\\yyzypublic\\.openclaw\\workspace\\build_1084.png', fullPage: false });
}

// Get status indicators
const statusElements = await page.evaluate(() => {
  // Look for status-related elements
  const results = [];

  // Find elements with status classes
  const statusEls = document.querySelectorAll('[class*="status"], [class*="success"], [class*="fail"], [class*="running"], [class*="pending"]');
  statusEls.forEach(el => {
    if (el.textContent.trim()) {
      results.push({ tag: el.tagName, class: el.className, text: el.textContent.trim().substring(0, 100) });
    }
  });

  return results.slice(0, 20);
});

console.log('Status elements:', JSON.stringify(statusElements, null, 2));

// Get full body text after clicking 1084
const bodyText = await page.evaluate(() => document.body.innerText);
console.log('\nBody text after click (first 2000 chars):');
console.log(bodyText.substring(0, 2000));

await browser.close();
